import { initialState } from './../products.state';
import { createReducer, on } from '@ngrx/store';
import * as productActions from '../actions/product.actions';
export const productReducer = createReducer(initialState, on(productActions.toggleProductCode, state => {
  return Object.assign(Object.assign({}, state), {
    showProductCode: !state.showProductCode
  });
}), on(productActions.setCurrentProduct, (state, action) => {
  return Object.assign(Object.assign({}, state), {
    currentProduct: action.product
  });
}), on(productActions.clearCurrentProduct, state => {
  return Object.assign(Object.assign({}, state), {
    currentProduct: null
  });
}), on(productActions.initializeCurrentProduct, state => {
  return Object.assign(Object.assign({}, state), {
    currentProduct: {
      id: 0,
      productName: "New",
      productCode: 0
    }
  });
}));
